JSType meet(JSType that) {
  List alternates = newArrayList();
  boolean found = false;
  for (JSType alternate : this.alternates) {
    if (!alternate.isSubtype(that)) {
      alternates.add(alternate);
    } else { found = true; }
  }

  if (! found) {
    if (that.isSubtype(this)) {
      alternates.add(that);
    } else { return JSType. bottom(); }
  }

  if (at least one alternate is object type) { return get Native type(JSType Native.object()); }
  if ( alternates.isEmpty()) { return bottom(); }
  return new UnionTypeBuilder(this. registry) . add alternates. build();
}

